import React from "react";

export default function StatsCard({ number, text, link }) {
  return (
    <div style={styles.card}>
      {link ? (
        <a
          href={link}
          target="_blank"
          rel="noopener noreferrer"
          style={styles.number}
        >
          {number}
        </a>
      ) : (
        <div style={styles.number}>{number}</div>
      )}

      <div style={styles.text}>{text}</div>
    </div>
  );
}

const styles = {
  card: {
    backgroundColor: "white",
    width: "250px",
    padding: "2rem",
    borderRadius: "16px",
    boxShadow: "0 2px 12px rgba(0,0,0,.08)",
    textAlign: "center",
  },

  number: {
    color: "#f597a0",
    fontSize: "1.4rem",
    fontWeight: "700",
    marginBottom: "1rem",
    textDecoration: "none",
    display: "block",
    cursor: "pointer",
  },

  text: {
    color: "#64748b",
    lineHeight: "1.6",
  },
};
